import { useEffect } from "react";
import { useStorage } from "../hooks/useStorage";

export const ProgressBar = ({file, setFile}) => {
    const { progress, url } = useStorage(file);

    useEffect (() => {
      if(url){
        setFile(null)
      }
    }, [url, setFile])
      return (
    <div className="progress-bar" style={{width: progress + '%'}}>
      <span>
        {progress}%
      </span>
    </div>
  )
}
